import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../api/axios';

const Login = () => {
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        try {
            const response = await api.post('/api/auth/login', { username, password });

            // Сохраняем данные сессии
            localStorage.setItem('accessToken', response.data.accessToken);
            localStorage.setItem('userRole', response.data.role);
            localStorage.setItem('username', response.data.username);

            alert(`С возвращением, ${response.data.username}!`);
            navigate('/products'); 
        } catch (err) {
            alert('Ошибка входа: проверьте логин и пароль');
        }
    };

    return (
        <div style={styles.container}>
            <div style={styles.card}>
                <h2 style={styles.title}>Вход в систему</h2>

                {/* Текстовое окошко с данными админа */}
                <div style={styles.adminBadge}>
                    <span style={{ fontWeight: '700' }}>Тестовый доступ:</span>
                    <code style={styles.code}>admin / admin123</code>
                </div>

                <form onSubmit={handleLogin}>
                    <div style={styles.inputGroup}>
                        <label style={styles.label}>Логин</label>
                        <input
                            style={styles.input}
                            type="text"
                            placeholder="Введите логин"
                            value={username}
                            onChange={(e) => setUsername(e.target.value)}
                            required
                        />
                    </div>
                    <div style={styles.inputGroup}>
                        <label style={styles.label}>Пароль</label>
                        <input
                            style={styles.input}
                            type="password"
                            placeholder="Введите пароль"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                        />
                    </div>
                    <button style={styles.button} type="submit">Войти</button>
                </form>
            </div>
        </div>
    );
};

const styles = {
    container: {
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        minHeight: '100vh',
        backgroundColor: '#f8f9fa',
        fontFamily: "'Inter', sans-serif",
    },
    card: {
        backgroundColor: '#ffffff',
        padding: '40px',
        borderRadius: '24px',
        boxShadow: '0 15px 35px rgba(0,0,0,0.1)',
        width: '100%',
        maxWidth: '380px',
        textAlign: 'center',
    },
    title: {
        marginBottom: '10px',
        fontSize: '24px',
        color: '#1a1a1a',
    },
    adminBadge: {
        backgroundColor: '#e3f2fd',
        color: '#007AFF',
        padding: '12px',
        borderRadius: '12px',
        fontSize: '13px',
        marginBottom: '25px',
        border: '1px solid #bbdefb',
        display: 'flex',
        flexDirection: 'column',
        gap: '5px'
    },
    code: {
        backgroundColor: '#fff',
        padding: '2px 8px',
        borderRadius: '4px',
        fontWeight: 'bold',
        fontSize: '14px',
        color: '#333'
    },
    inputGroup: {
        marginBottom: '20px',
        textAlign: 'left',
    },
    label: {
        display: 'block',
        marginBottom: '8px',
        fontSize: '14px',
        fontWeight: '600',
        color: '#666',
    },
    input: {
        width: '100%',
        padding: '12px 16px',
        borderRadius: '12px',
        border: '1.5px solid #eee',
        fontSize: '16px',
        outline: 'none',
        boxSizing: 'border-box',
    },
    button: {
        width: '100%',
        padding: '14px',
        borderRadius: '12px',
        border: 'none',
        backgroundColor: '#007AFF',
        color: '#fff',
        fontSize: '16px',
        fontWeight: '600',
        cursor: 'pointer',
        transition: '0.2s',
    }
};

export default Login;
